```
extra_files:
  proposer-settings.json: |
    {
      "default_config": {
        "fee_recipient": "0x8943545177806ED17B9F23F0a21ee5948eCaa776",
        "builder": {
          "enabled": true,
          "gas_limit": 150000000,
          "relays": ["http://buildoor:8080"],
          "max_execution_payment": 200000000
        }
      }
    }
```
